1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string; cursed?: boolean; enchantment?: number };
13	type Step = { op?: string; items: Item[] };
14	type Customer = { yearsWithMHPCO: number };
15	type Scenario = { customer: Customer; steps: Step[] };
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	const BLOCK_BASE_PREMIUM = 60;
19	
20	function computeQuotePremium(
21	  items: Item[],
22	  customer: Customer,
23	  quoteIndex: number,
24	): number {
25	  const componentCountsByType = new Map<string, number>();
26	  let itemAdjustedSum = 0;
27	  let policyBasePremium = 0;
28	  for (const item of items) {
29	    if (!(item.type in BASE_PREMIUM_BY_ITEM_TYPE)) {
30	      throw new Error(`Unknown item type: ${item.type}`);
31	    }
32	    if (COMPONENT_TYPES.has(item.type)) {
33	      componentCountsByType.set(
34	        item.type,
35	        (componentCountsByType.get(item.type) ?? 0) + 1,
36	      );
37	    } else {
38	      const base = BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
39	      let itemPremium = base;
40	      if (item.cursed) {
41	        itemPremium += base * 0.5;
42	      }
43	      if (item.enchantment !== undefined && item.enchantment >= 5) {
44	        itemPremium += base * 0.3;
45	      }
46	      itemPremium += base * 0.1;
47	      itemAdjustedSum += itemPremium;
48	      policyBasePremium += base;
49	    }
50	  }
51	  for (const [type, count] of componentCountsByType) {
52	    if (count === 3) {
53	      itemAdjustedSum += BLOCK_BASE_PREMIUM + BLOCK_BASE_PREMIUM * 0.1;
54	      policyBasePremium += BLOCK_BASE_PREMIUM;
55	    } else {
56	      const componentBase = BASE_PREMIUM_BY_ITEM_TYPE[type] ?? 0;
57	      itemAdjustedSum += count * (componentBase + componentBase * 0.1);
58	      policyBasePremium += count * componentBase;
59	    }
60	  }
61	  let loyaltyDiscount = 0;
62	  if (customer.yearsWithMHPCO >= 2) {
63	    loyaltyDiscount = policyBasePremium * 0.2;
64	  }
65	  let followUpDiscount = 0;
66	  if (quoteIndex >= 1) {
67	    followUpDiscount = policyBasePremium * 0.15;
68	  }
69	  return Math.ceil(
70	    itemAdjustedSum - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
71	  );
72	}
73	
74	export function processScenario(scenario: unknown): unknown {
75	  const { customer, steps } = scenario as Scenario;
76	  const results: { premium: number }[] = [];
77	  let quoteIndex = 0;
78	  for (const step of steps) {
79	    const premium = computeQuotePremium(step.items, customer, quoteIndex);
80	    results.push({ premium });
81	    quoteIndex += 1;
82	  }
83	  return { results };
84	}
